function isErycSearchCrawler() {
  const userAgent = navigator.userAgent.toLowerCase();

  const botKeywords = [
    'bot',
    'crawler',
    'spider',
    'googlebot',
    'bingbot',
    'yandexbot',
    'silktide',
    'sitesearch360'
    // Add other search crawler user agent keywords as needed
  ];

  return botKeywords.some(keyword => userAgent.includes(keyword));
}

function ERYC_CookieHide_setCookie(cname, cvalue, exdays, exmins, includeDomain) {
	var d = new Date();
	exdays = exdays * 24 * 60 * 60 * 1000;
	if (exmins > 0) {
		exdays = exmins * 1000 * 60;
	}
	d.setTime(d.getTime() + exdays);
	var expires = "expires="+d.toUTCString();
	if (exdays == 0) {
		expires = "";
	}

	var domain = includeDomain != undefined == includeDomain == true ? '; domain=' + window.location.hostname.replace(/^www\./, '.') : '';

	document.cookie = cname + "=" + cvalue + ";" + expires + ";path=/" + domain;
}
function ERYC_CookieHide_getCookie(cname) {
	var name = cname + "=";
	var decodedCookie = decodeURIComponent(document.cookie);
	var ca = decodedCookie.split(';');
	for(var i = 0; i <ca.length; i++) {
		var c = ca[i];
		while (c.charAt(0) == ' ') {
			c = c.substring(1);
		}
		if (c.indexOf(name) == 0) {
			return c.substring(name.length, c.length);
		}
	}
	return "";
}
function ERYC_CookieHide_deleteCookie(cname) {
	document.cookie = cname + '=; Path=/; Expires=Thu, 01 Jan 1970 00:00:01 GMT;';
}

(function ($) {
  $(document).ready(function() {
    var er_cookie_hide_el             = $('.er-cookie-close');
    var er_cookie_hide_id             = '';
    var er_cookie_hide_cookie_name    = '';
    var er_cookie_hide_cookie_expire  = 365;
    var er_cookie_hide_cookie_mins    = 0;

    er_cookie_hide_el.each(function(idx, obj){
      er_cookie_hide_id               = $(this).attr('data-id');
      er_cookie_hide_cookie_name      = 'er_cookie_hide_' + $(this).attr('data-cookie');
      er_cookie_hide_cookie_expire    = parseInt($(this).attr('data-expire'));

      if (er_cookie_hide_cookie_expire == 0) {
        er_cookie_hide_cookie_mins = 20;
