// Get query string parameter as string
function getUrlParameter(name, source) {
  name = name.replace(/[\[]/, '\\[').replace(/[\]]/, '\\]');
  var regex = new RegExp('[\\?&]' + name + '=([^&#]*)');
  var results = source != null ? regex.exec(source) : regex.exec(location.search);
  return results === null ? '' : decodeURIComponent(results[1].replace(/\+/g, ' '));
};

// Get URL parameters as array
function getUrlParameters(source) {
  var query   = source != null ? source.slice(1) : window.location.search.slice(1);
  var querys  = query.split('&');
  var array   = {};

  if (query.length > 0) {
    for (var i = 0; i < querys.length; i++) {
      var split = querys[i].split('=');
      array[split[0]] = decodeURIComponent(split[1].replace(/\+/g, ''));
    }
  }

  return array;
};

// Add canonical link
function addErycCanonicalLink(url) {
  const head = document.head || document.getElementsByTagName('head')[0];
  let canonicalLink = document.querySelector('link[rel="canonical"]');

  if (canonicalLink) {
    // If a canonical link already exists, replace the href attribute
    canonicalLink.href = url;
  } else {
    // Create a new canonical link element
    canonicalLink = document.createElement('link');
    canonicalLink.rel = 'canonical';
    canonicalLink.href = url;
    head.appendChild(canonicalLink);
  }
}

// Sanitize HTML
function sanitizeHTML(input) {
  // Create a new DOMParser
  const parser = new DOMParser();

  // Parse the input as HTML
  const doc = parser.parseFromString(input, 'text/html');

  // Get the sanitized HTML content
  const sanitizedHTML = doc.body.innerHTML;

  return sanitizedHTML;
}

function sanitizeQuerystring(input) {
  // Define a regex pattern for alphanumeric characters and basic punctuation
  const regex = /[a-zA-Z0-9.,!?;: ]/g;

  // Use match to extract matching characters
  const matches = input.match(regex);

  // If matches are found, join them into a string; otherwise, return an empty string
  return matches ? matches.join('') : '';
}

(function ($) {

  $(window).on('load', function() {

    if ($('[data-particle-inject-to]').length > 0) {

      var data_particle_inject_froms = [];

      $('[data-particle-inject-to]').each(function () {
          var to = $(this).attr('data-particle-inject-to');
          var $target = $(this);

          // find ALL matching "from" elements
          var $froms = $('section[id^="g-inject"] [data-particle-inject-from="' + to + '"]');

          if ($froms.length > 0) {
              // move them all
              $froms.appendTo($target);

              // record what type was moved
              data_particle_inject_froms.push(to);
          }
      });

      $.each(data_particle_inject_froms, function(i, o){

        $('section[id^="g-inject"] [data-particle-inject-from="' + o + '"]').remove();

      })

    }

    ErycMobileInjectTo();


  });

  $(window).on('resize', function() {
    ErycMobileInjectTo();
  });

})(jQuery)

function ErycMobileInjectTo() {

  if (window.innerWidth < 768) {

    if (jQuery('[data-mobile-inject-to]').length > 0) {

      jQuery('[data-mobile-inject-to]').each(function(mi_i, mi_o){

        var to = jQuery(this).attr('data-mobile-inject-to');

        if (jQuery('[data-mobile-inject-id="' + to + '"] .tmp-mobile-inject').length == 0) {
          jQuery('[data-mobile-inject-id="' + to + '"]').prepend('<div class="tmp-mobile-inject"></div>');
        }

        if (jQuery('[data-mobile-inject-id="' + to + '"]').length > 0 && jQuery(this).find('[data-mobile-inject-id]').length == 0) {

          jQuery(this).before('<div class="hidden" data-mobile-inject-idx="' + mi_i + '"></div>');

          jQuery(this).attr('data-mobile-inject-idx-desktop', mi_i);

          jQuery(this).appendTo(jQuery('[data-mobile-inject-id="' + to + '"] .tmp-mobile-inject'));

        }

      });

      jQuery('.tmp-mobile-inject').each(function() {
        jQuery(this).children().insertBefore(this);
        jQuery(this).remove();
      });

    }

  }

  else {

    if (jQuery('[data-mobile-inject-idx-desktop]').length > 0) {

      jQuery('[data-mobile-inject-idx-desktop]').each(function(di_i, di_o){

        var attr_idx = jQuery(this).attr('data-mobile-inject-idx-desktop');

        if (jQuery('[data-mobile-inject-idx="' + attr_idx + '"]').length > 0) {
          jQuery(this).insertBefore(jQuery('[data-mobile-inject-idx="' + attr_idx + '"]'));
          jQuery(this).removeAttr('data-mobile-inject-idx-desktop');
        }

      });

      jQuery('[data-mobile-inject-idx], [data-mobile-inject-idx-desktop]').remove()


    }

  }

}

(function ($) {
  // Open accordion
  function openAccordion(el) {
    el.parent().toggleClass('open').toggleClass('closed');
    el.toggleClass('open').toggleClass('closed');
    $.when(el.next('.content').slideToggle()).then(function(){
      if (el.parents('.slick-slider')) {
        var slick_parent = el.parents('.slick-slider');
        slick_parent.find(".slick-slide").height("auto");
        slick_parent.slick("setOption", '', '', true);
      }
    })
  }
  $(window).on('load', function() {
    $('.er-accordion').on('click', '.accordion-header', function(e){
      e.preventDefault();
      openAccordion($(this));

      $(this).mouseleave(function(me){
        $(this).blur();
        return false;
      })

    })

    // Scroll
    function er_page_acc_hash() {
      var er_window_hash = window.location.hash;
      if (!er_window_hash) return;

      var targetId = er_window_hash.slice(1);
      var $target = $('#' + targetId);

      if ($target.length === 0) return;

      // If this accordion is nested, open all its parent accordions first
      var $parents = $target.parents('.accordion');
      $parents.each(function() {
        var $parentAcc = $(this);
        if (!$parentAcc.hasClass('open')) {
          $parentAcc.find('> .accordion-header')[0].click();
        }
      });

      // Then open the target accordion itself (if not already open)
      if (!$target.hasClass('open')) {
        $target.find('> .accordion-header')[0].click();
      }

      // Finally, scroll smoothly to the target accordion
      setTimeout(function() {
        document.getElementById(targetId).scrollIntoView({
          behavior: 'smooth',
          block: 'start'
        });
      }, 300); // small delay ensures animation completes
    }

    er_page_acc_hash();
    $(window).on('hashchange smoothScrollFinished', function(e){
      er_page_acc_hash();
    })

    // Tags
    if ($('.er-accordion .accordion-tags').length > 0) {

      $('.er-accordion').each(function(i, o){

        var el = $(this);

        var tag_id_arr  = [];
        var tag_arr     = [];

        if ($(this).find('.accordion-tag').length > 0) {

          $(this).find('.accordion-tag').each(function(){

            var tag_id  = $(this).attr('data-id');
            var tag_txt = $(this).text().trim();

            if (tag_id_arr.indexOf(tag_id) == -1) {
              tag_id_arr.push(tag_id);
              tag_arr.push({
                id: tag_id,
                text: tag_txt
              });
            }

          })

          tag_arr.sort(function(a, b){
            aSort = a.id;
            bSort = b.id;

            if (aSort < bSort) {
              return -1;
            }
            if (aSort > bSort) {
              return 1;
            }
            else {
              return 0;
            }

          })

          el.find('#accordion-tag-selector-loader').remove();

          $.each(tag_arr, function(k, v){

            el.find('.accordion-tags-selector').append('<a href="#" class="er-link-styled " id="accordion-tag-selector-' + v.id + '" data-id="' + v.id + '" data-search="' + v.text + '">' + v.text + '</a>');

          })

        }

      })

      $('.er-accordion .accordion-tags-selector').on('click', 'a', function(e){

        e.preventDefault();

        var el_parent = $(this).parents('.er-accordion');
        var click_id  = $(this).attr('data-id');

        if (!$(this).hasClass('active')) {

          $(this).parent().find('.active').removeClass('active');
          $(this).addClass('active');

          if (click_id != 'all') {

            el_parent.find('> .accordions > .accordion').addClass('hidden');
            el_parent.find('.accordion-tag[data-id="' + click_id + '"]').parents('.accordion').removeClass('hidden');

          }
          else {
            el_parent.find('> .accordions > .accordion').removeClass('hidden');
          }

        }

      })

    }

    // Reorder
    $('.er-accordion .accordion-reorder-btns a').click(function(e){
      e.preventDefault();

      if (!$(this).hasClass('active')) {
        $(this).parent().find('.active').removeClass('active');
        $(this).addClass('active');

        var mode = $(this).attr('data-id');

        var order_arr = [];

        $(this).parents('.er-accordion').find('.accordions > .accordion').each(function(i, o){
          var arr = [{
            id: $(this).attr('id'),
            latest: $(this).attr('data-order-latest'),
            atoz: $(this).attr('data-order-atoz')
          }]
          order_arr.push(arr);
        })

        var order_arr_sorted = order_arr.slice(0);

        if (mode == 'latest') {
          order_arr_sorted.sort(function(a, b){
            aSort = parseInt(a[0].latest);
            bSort = parseInt(b[0].latest);

