    jQuery('body').css({"overflow": "hidden"});

    const $modalClose = jQuery('.modal-close');

    $modalClose.click(function(e) {
      e.preventDefault();
      modalClose($clickedElement, customClass);
    });

    $modalClose.keydown(function(e) {
      if (parseInt(e.keyCode) === 13) {
        e.preventDefault();
        modalClose($clickedElement, customClass);
      }
