window.applyTopicFilter = function (topicLabel) {
    const topicValue = topicLabel.trim();

    // Defer to escape the SS360 innerHTML execution context
    setTimeout(() => {
        const doc = window.parent?.document || document;

        // Find only checkboxes inside the "Topic" filter section
        const topicSection = doc.querySelector('section[aria-label="Topic"]');

        if (!topicSection) {
            return;
        }

        const checkboxes = Array.from(topicSection.querySelectorAll('.ss360-multiselect__checkbox'));

        const checkbox = checkboxes.find(cb =>
            cb.value.trim().toLowerCase() === topicValue.toLowerCase()
        );

        if (!checkbox) {
            return;
        }

        // Toggle behaviour: if already checked, uncheck it
        const willCheck = !checkbox.checked;

        // Uncheck all others first (single-select behaviour)
        checkboxes.forEach(cb => (cb.checked = false));

        // Apply the new toggle state
        checkbox.checked = willCheck;

        // Dispatch the change event so SS360 refreshes results
        checkbox.dispatchEvent(new Event('change', { bubbles: true }));
    }, 0);
};

